    int fd; // file descriptor
    int uv, als, ir; // UV, ALS, and IR data
    FILE *file; // file pointer for logging data
    time_t rawtime; // for timestamp
    struct tm *timeinfo; // for timestamp
    char buffer[80]; // for timestamp

    // Initialize wiringPi
    if(wiringPiSetup() == -1) {
        fprintf(stderr, "Failed to initialize wiringPi\n");
        return 1;
