    fd = wiringPiI2CSetup(SI1133_ADDR);
    if(fd == -1) {
        fprintf(stderr, "Failed to initialize I2C connection\n");
        return 1;
    }

    // Open file for logging data
    file = fopen("light_data.log", "w");
    if(file == NULL) {
        fprintf(stderr, "Failed to open file for logging\n");
        return 1;
    }

    // Main loop
    while(1) {
        // Read UV, ALS, and IR data
        uv = wiringPiI2CReadReg8(fd, 0x2C);
        als = wiringPiI2CReadReg8(fd, 0x2B);
        ir = wiringPiI2CReadReg8(fd, 0x2D);

        // Handle errors
        if(uv == -1 || als == -1 || ir == -1) {
            fprintf(stderr, "Failed to read from I2C\n");
            continue;
        }

        // Get current time
        time(&rawtime);
        timeinfo = localtime(&rawtime);
        strftime(buffer, sizeof(buffer), "%d-%m-%Y %H:%M:%S", timeinfo);
        fprintf(file, "%s, UV: %d, ALS: %d, IR: %d\n", buffer, uv, als, ir);

        // Wait for 1 second
        sleep(1);
    }

    // Close file and exit
    fclose(file);
    return 0;
}
