void signal_handler(int signal) {
    program_running = 0;
    fprintf(stderr, "\nCaught signal %d, terminating...\n", signal);
}

// Function to initialize the Si1133 sensor
int init_si1133(int i2c_handle) {
    // Check Part ID
    int part_id = i2cReadByteData(i2c_handle, REG_PART_ID);
    if (part_id < 0) {
        fprintf(stderr, "Error reading Part ID: %d\n", part_id);
        return -1;
    }

    if (part_id != 0x33) {
        fprintf(stderr, "Error: Part ID mismatch. Expected 0x33, got 0x%X\n", part_id);
        return -1;
    }

    // Initialize the sensor (example configuration)
    // Refer to the Si1133 datasheet for the correct register settings
    if (i2cWriteByteData(i2c_handle, 0x02, 0x01) < 0) {
        fprintf(stderr, "Error writing to register 0x02\n");
        return -1;
    }

    return 0;
}

// Function to read sensor data
int read_si1133_data(int i2c_handle, uint16_t *ambient, uint16_t *infrared, uint16_t *uv_index) {
    // Read ambient light data
    int vis_data0 = i2cReadByteData(i2c_handle, REG_ALS_VIS_DATA0);
    int vis_data1 = i2cReadByteData(i2c_handle, REG_ALS_VIS_DATA1);
    if (vis_data0 < 0 || vis_data1 < 0) {
        fprintf(stderr, "Error reading ambient light data\n");
        return -1;
    }
    *ambient = (uint16_t)((vis_data1 << 8) | vis_data0);

    // Read infrared data
    int ir_data0 = i2cReadByteData(i2c_handle, REG_ALS_IR_DATA0);
    int ir_data1 = i2cReadByteData(i2c_handle, REG_ALS_IR_DATA1);
    if (ir_data0 < 0 || ir_data1 < 0) {
        fprintf(stderr, "Error reading infrared data\n");
        return -1;
