    *infrared = (uint16_t)((ir_data1 << 8) | ir_data0);

    // Read UV index data
    int uv_data0 = i2cReadByteData(i2c_handle, REG_UV_INDEX0);
    int uv_data1 = i2cReadByteData(i2c_handle, REG_UV_INDEX1);
    if (uv_data0 < 0 || uv_data1 < 0) {
        fprintf(stderr, "Error reading UV index data\n");
        return -1;
    }
    *uv_index = (uint16_t)((uv_data1 << 8) | uv_data0);

    return 0;
}

