        gpioTerminate();
        return 1;
    }

    // Initialize Si1133 sensor
    if (init_si1133(i2c_handle) != 0) {
        fprintf(stderr, "Si1133 initialisation failed\n");
        i2cClose(i2c_handle);
        gpioTerminate();
        return 1;
    }

