    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (program_running) {
        uint16_t ambient, infrared, uv_index;

        // Read sensor data
        if (read_si1133_data(i2c_handle, &ambient, &infrared, &uv_index) == 0) {
