                fprintf(stderr, "Error logging data\n");
            }
        } else {
            fprintf(stderr, "Error reading sensor data. Retrying...\n");
        }

        // Delay for 1 second
        time_sleep(1.0);
    }

    // Close I2C connection and terminate pigpio
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

