#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <stdbool.h>
#include <string.h>
#include <time.h>
#include <signal.h>
#include <unistd.h>
#include <pigpio.h>

// Constants
#define LM75B_ADDR 0x48
#define FAN_GPIO 18
#define PWM_FREQUENCY 1000 // Hz
#define TEMP_THRESHOLD_LOW 40.0
#define TEMP_THRESHOLD_HIGH 60.0
#define TEMP_THRESHOLD_CRITICAL 70.0
#define PWM_MAX 255
#define LOG_SIZE 100
#define SLEEP_DURATION 1 // seconds

// Data Structures
typedef struct {
    float temperature;
    int fan_speed;
    time_t timestamp;
} LogEntry;

typedef struct {
    LogEntry entries[LOG_SIZE];
    int head;
    int count;
} CircularBuffer;

// Global Variables
int i2c_handle;
CircularBuffer log_buffer;
bool running = true;

// Function Prototypes
float read_temperature(int i2c_handle);
int calculate_fan_speed(float temperature);
void set_fan_speed(int gpio_pin, int pwm_value);
void log_data(CircularBuffer *buffer, float temperature, int fan_speed);
void print_log(CircularBuffer *buffer);
void signal_handler(int signal);

// Function to read temperature from LM75B
float read_temperature(int i2c_handle) {
    char buf[2];
    float temperature;
    int raw_temp;

    if (i2cReadDevice(i2c_handle, buf, 2) != 2) {
        fprintf(stderr, "Error reading temperature from LM75B.\n");
        return -100.0; // Indicate error
    }

    raw_temp = (buf[0] << 8) | buf[1];
    temperature = (float)(raw_temp >> 5) * 0.125;

    return temperature;
}

// Function to calculate fan speed based on temperature
int calculate_fan_speed(float temperature) {
    if (temperature < TEMP_THRESHOLD_LOW) {
        return 0;
    } else if (temperature < TEMP_THRESHOLD_HIGH) {
        return (int)((temperature - TEMP_THRESHOLD_LOW) / (TEMP_THRESHOLD_HIGH - TEMP_THRESHOLD_LOW) * PWM_MAX);
    } else if (temperature < TEMP_THRESHOLD_CRITICAL) {
        return (int)((temperature - TEMP_THRESHOLD_HIGH) / (TEMP_THRESHOLD_CRITICAL - TEMP_THRESHOLD_HIGH) * (PWM_MAX - 255)) + 255;
    } else {
        return PWM_MAX;
    }
}

// Function to set fan speed using PWM
void set_fan_speed(int gpio_pin, int pwm_value) {
    gpioPWM(gpio_pin, pwm_value);
}

// Function to log data to circular buffer
void log_data(CircularBuffer *buffer, float temperature, int fan_speed) {
    buffer->entries[buffer->head].temperature = temperature;
    buffer->entries[buffer->head].fan_speed = fan_speed;
    buffer->entries[buffer->head].timestamp = time(NULL);
    buffer->head = (buffer->head + 1) % LOG_SIZE;
    if (buffer->count < LOG_SIZE) {
        buffer->count++;
    }
}

// Function to print the contents of the circular buffer
void print_log(CircularBuffer *buffer) {
    printf("\n--- Log of Last %d Entries ---\n", buffer->count);
    for (int i = 0; i < buffer->count; i++) {
        int index = (buffer->head - i + LOG_SIZE) % LOG_SIZE;
        printf("Entry %d: Temperature = %.2f°C, Fan Speed = %d, Timestamp = %ld\n",
               i + 1, buffer->entries[index].temperature, buffer->entries[index].fan_speed, buffer->entries[index].timestamp);
    }
    printf("--- End of Log ---\n\n");
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = false;
    printf("\nCaught signal %d, exiting gracefully...\n", signal);
    gpioPWM(FAN_GPIO, 0); // Stop the fan
    i2cClose(i2c_handle);
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Open I2C connection
    i2c_handle = i2cOpen(1, LM75B_ADDR, 0); // Bus 1, address 0x48, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C connection: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Configure fan GPIO as output
    gpioSetMode(FAN_GPIO, PI_OUTPUT);

    // Initialize circular buffer
    log_buffer.head = 0;
    log_buffer.count = 0;

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    // Main loop
    while (running) {
        // Read temperature
        float temperature = read_temperature(i2c_handle);
        if (temperature < -99.0) {
            fprintf(stderr, "Error reading temperature, exiting.\n");
            running = false;
            continue;
        }

        // Calculate fan speed
        int fan_speed = calculate_fan_speed(temperature);

        // Set fan speed
        set_fan_speed(FAN_GPIO, fan_speed);

        // Log data
        log_data(&log_buffer, temperature, fan_speed);

        // Print log
        print_log(&log_buffer);

        // Sleep for a short period
        sleep(SLEEP_DURATION);
    }

    // Cleanup (should not reach here if signal handler works correctly)
    gpioPWM(FAN_GPIO, 0);
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

