    float temperature;
    int pwm_duty_cycle;
    time_t timestamp;
} ThermalData;

// Global Variables
int i2c_handle;
ThermalData thermal_buffer[BUFFER_SIZE];
int buffer_index = 0;
bool running = true;

// Function Prototypes
int initialize_pigpio();
int initialize_i2c();
float read_temperature(int i2c_handle);
int set_fan_speed(int gpio_pin, int duty_cycle);
int add_to_buffer(ThermalData data);
void print_buffer();
void log_data(ThermalData data);
void signal_handler(int signal);

// Function Definitions

// Initializes the pigpio library.
int initialize_pigpio() {
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return -1;
    }
    return 0;
}

// Initializes the I2C communication.
int initialize_i2c() {
    i2c_handle = i2cOpen(1, LM75B_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        return -1;
    }
    return 0;
}

// Reads the temperature from the LM75B sensor.
float read_temperature(int i2c_handle) {
    char buf[2];
    int bytes_read = i2cReadDevice(i2c_handle, buf, 2);
    if (bytes_read != 2) {
        fprintf(stderr, "Failed to read temperature: %d\n", bytes_read);
        return -273.15; // Return absolute zero on error
    }
    int16_t raw_temp = (buf[0] << 8) | buf[1];
    float temperature = (float)raw_temp / 256.0;
    return temperature;
}

// Sets the fan speed using PWM.
int set_fan_speed(int gpio_pin, int duty_cycle) {
    gpioPWM(gpio_pin, duty_cycle);
    return 0;
}

// Adds data to the circular buffer.
int add_to_buffer(ThermalData data) {
    thermal_buffer[buffer_index] = data;
    buffer_index = (buffer_index + 1) % BUFFER_SIZE;
    return 0;
}

// Prints the contents of the circular buffer.
void print_buffer() {
    printf("Temperature Buffer:\n");
    for (int i = 0; i < BUFFER_SIZE; i++) {
        int index = (buffer_index + i) % BUFFER_SIZE;
        printf("  Index: %d, Temperature: %.2f, PWM: %d\n", index, thermal_buffer[index].temperature, thermal_buffer[index].pwm_duty_cycle);
    }
}

// Logs the data to a file.
void log_data(ThermalData data) {
    FILE *fp = fopen(LOG_FILE, "a");
    if (fp == NULL) {
        fprintf(stderr, "Failed to open log file\n");
        return;
    }

    struct tm *timeinfo;
    char timestamp[80];
    time_t now = time(NULL);
    timeinfo = localtime(&now);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(fp, "%s,%.2f,%d\n", timestamp, data.temperature, data.pwm_duty_cycle);
    fclose(fp);
}

// Signal handler for graceful shutdown.
void signal_handler(int signal) {
    printf("Caught signal %d, exiting gracefully...\n", signal);
    running = false;
    gpioPWM(PWM_GPIO, 0); // Stop the fan
    gpioTerminate();
    exit(0);
}

int main() {
    // Initialize pigpio
    if (initialize_pigpio() != 0) {
        return 1;
    }

    // Initialize I2C
    if (initialize_i2c() != 0) {
        gpioTerminate();
        return 1;
    }

    // Set PWM frequency
    gpioSetPWMfrequency(PWM_GPIO, PWM_FREQUENCY);

    // Set PWM range
    gpioSetPWMrange(PWM_GPIO, 255);

    // Set signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    float target_temperature = 35.0;
    int fan_duty_cycle = 0;
    time_t last_fan_change_time = time(NULL);
    float last_temperature = -273.15; // Initialize to absolute zero

    printf("Thermal monitoring started. Press Ctrl+C to exit.\n");

    while (running) {
        // Read temperature
        float temperature = read_temperature(i2c_handle);
        if (temperature < -273.0) {
            fprintf(stderr, "Error reading temperature, exiting...\n");
            running = false;
            continue;
        }

        // Calculate error
        float error = temperature - target_temperature;

        // Adjust fan speed based on error
        if (fabs(error) > TEMP_HYSTERESIS) {
            if (error > 0) {
                fan_duty_cycle += 10;
                if (fan_duty_cycle > 255) fan_duty_cycle = 255;
            } else {
                fan_duty_cycle -= 10;
                if (fan_duty_cycle < 0) fan_duty_cycle = 0;
            }

            // Debounce fan control
            time_t current_time = time(NULL);
            if (difftime(current_time, last_fan_change_time) > 0.5) {
                set_fan_speed(PWM_GPIO, fan_duty_cycle);
                last_fan_change_time = current_time;
            }
        }

        // Add data to buffer
        ThermalData data;
        data.temperature = temperature;
        data.pwm_duty_cycle = fan_duty_cycle;
        data.timestamp = time(NULL);
        add_to_buffer(data);

        // Log data
        log_data(data);

        // Print data to console
        printf("Temperature: %.2f C, Fan Speed: %d\n", temperature, fan_duty_cycle);

        // Sleep for 5 seconds
        sleep(5);
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioPWM(PWM_GPIO, 0); // Stop the fan
    gpioTerminate();

    return 0;
}

