#include <fcntl.h>
#include <sys/ioctl.h>
#include <linux/i2c-dev.h>
#include <pigpio.h>

// Constants
#define LM75B_ADDR 0x48
#define PWM_FREQUENCY 1000 // Hz
#define PWM_GPIO 18
#define BUFFER_SIZE 10

// Sensor data structure
typedef struct {
    time_t timestamp;
    float temperature;
} sensor_data_t;

// Global variables
static volatile int running = 1;
static int i2c_fd;
static sensor_data_t sensor_buffer[BUFFER_SIZE];
static int buffer_index = 0;

// Function prototypes
float read_temperature(int fd);
void set_fan_speed(int gpio, int duty_cycle);
void add_to_buffer(sensor_data_t data, sensor_data_t *buffer, int *index);
void print_buffer(sensor_data_t *buffer, int index);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    running = 0;
    printf("\nCaught signal %d, exiting gracefully.\n", signal);
}

// Function to read temperature from LM75B sensor
float read_temperature(int fd) {
    unsigned char buf[2];
    int ret;

    // Read temperature register (0x00)
    ret = i2c_smbus_read_word_data(fd, 0x00, buf);
    if (ret < 0) {
        fprintf(stderr, "Error reading temperature: %s\n", strerror(errno));
        return -273.15; // Return absolute zero as error
    }

    // Convert raw data to Celsius
    int16_t temp_raw = (buf[0] << 8) | buf[1];
    float temperature = (float)temp_raw / 256.0;

    return temperature;
}

// Function to set fan speed using PWM
void set_fan_speed(int gpio, int duty_cycle) {
    gpioPWM(gpio, duty_cycle);
}

// Function to add data to the circular buffer
void add_to_buffer(sensor_data_t data, sensor_data_t *buffer, int *index) {
    buffer[*index] = data;
    *index = (*index + 1) % BUFFER_SIZE;
}

// Function to print the contents of the circular buffer
void print_buffer(sensor_data_t *buffer, int index) {
    printf("\nSensor Data Log (Circular Buffer):\n");
    for (int i = 0; i < BUFFER_SIZE; i++) {
        int buffer_index = (index + i) % BUFFER_SIZE;
        time_t timestamp = buffer[buffer_index].timestamp;
        float temperature = buffer[buffer_index].temperature;
        printf("[%ld] Temperature: %.2f\n", timestamp, temperature);
    }
}

int main() {
    int duty_cycle = 0;
    float temperature;
    struct timespec ts;

    // Initialize pigpio library
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed: %s\n", strerror(errno));
        return 1;
    }

    // Open I2C device
    i2c_fd = open("/dev/i2c-1", O_RDWR);
    if (i2c_fd < 0) {
        fprintf(stderr, "Failed to open I2C device: %s\n", strerror(errno));
        gpioTerminate();
        return 1;
    }

    // Set I2C slave address
    if (ioctl(i2c_fd, I2C_SLAVE, LM75B_ADDR) < 0) {
        fprintf(stderr, "Failed to set I2C slave address: %s\n", strerror(errno));
        close(i2c_fd);
        gpioTerminate();
        return 1;
    }

    // Set PWM frequency and GPIO mode
    gpioSetMode(PWM_GPIO, PI_OUTPUT);
    gpioSetPWMfrequency(PWM_GPIO, PWM_FREQUENCY);
    gpioSetPWMrange(PWM_GPIO, 255);

    // Set up signal handlers
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    printf("Temperature monitoring and fan control started. Press Ctrl+C to exit.\n");

    // Main loop
    while (running) {
        // Read temperature
        temperature = read_temperature(i2c_fd);

        // Check for errors during temperature reading
        if (temperature < -273.15) {
            fprintf(stderr, "Error reading temperature, exiting.\n");
            running = 0;
            continue;
        }

        // Determine fan speed based on temperature
        if (temperature < 30.0) {
            duty_cycle = 0; // Fan off
        } else if (temperature < 50.0) {
            duty_cycle = 128; // 50% duty cycle
        } else {
            duty_cycle = 255; // Full speed
        }

        // Set fan speed
        set_fan_speed(PWM_GPIO, duty_cycle);

        // Add data to circular buffer
        clock_gettime(CLOCK_REALTIME, &ts);
        sensor_data_t data = {ts.tv_sec, temperature};
        add_to_buffer(data, sensor_buffer, &buffer_index);

        // Print the buffer to the console
        print_buffer(sensor_buffer, buffer_index);

        // Wait for 5 seconds
        sleep(5);
    }

    // Clean up
    close(i2c_fd);
    gpioPWM(PWM_GPIO, 0); // Turn off fan
    gpioTerminate();

    return 0;
}

