// Function to read temperature from MAX31855 via SPI
float readTemperature() {
    unsigned char data[MAX31855_DATA_SIZE];
    int retries = 0;

    while (retries < MAX_RETRIES) {
        if (wiringPiSPIDataRW(SPI_CHANNEL, data, MAX31855_DATA_SIZE) == -1) {
            fprintf(stderr, "SPI read failed (attempt %d): %s\n", retries + 1, strerror(errno));
            retries++;
            delay(10); // Short delay before retry
            continue;
        }

        // Check for errors in the status register (bit 0 of byte 3)
        if (data[3] & 0x07) {
            fprintf(stderr, "MAX31855 error: %s%s%s (attempt %d)\n",
