// Function to read temperature from MAX31855 thermocouple
float read_max31855(int spi_channel, int spi_speed) {
    unsigned char data[4];
    int i;
    float temperature = -999.0; // Default value to indicate error

    wiringPiSPISetup(spi_channel, spi_speed);

