static FILE *log_file = NULL;
static volatile sig_atomic_t program_running = 1;

// Structure for sensor data
typedef struct {
    float thermocouple_temperature;
    float internal_temperature;
    bool fault_detected;
} sensor_data_t;

// Function Prototypes
int initialize();
sensor_data_t read_max31855();
int control_fan(float temperature);
void log_data(float thermocouple_temperature, float internal_temperature, int fan_speed);
void signal_handler(int signal);

// Function to initialize the system
int initialize() {
    // Initialize wiringPi
    if (wiringPiSetup() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s\n", strerror(errno));
        return -1;
    }

    // Initialize SPI
    if (wiringPiSPISetup(SPI_CHANNEL, SPI_SPEED) == -1) {
        fprintf(stderr, "Error initializing SPI: %s\n", strerror(errno));
        return -1;
    }

    // Initialize PWM on FAN_GPIO
    pinMode(FAN_GPIO, PWM_OUTPUT);
    pwmSetMode(PWM_MODE_MS);
    pwmSetRange(100); // 0-100%

    // Open log file
    log_file = fopen(LOG_FILE, "a");
    if (log_file == NULL) {
        fprintf(stderr, "Error opening log file: %s\n", strerror(errno));
        return -1;
    }

    // Set up signal handler
    signal(SIGINT, signal_handler);
    signal(SIGTERM, signal_handler);

    return 0;
}

// Function to read data from MAX31855
sensor_data_t read_max31855() {
    sensor_data_t data = {0.0, 0.0, false};
    unsigned char spi_data[4];
    int retries = 0;

    while (retries < SPI_RETRIES) {
        // Read 4 bytes from SPI
        if (wiringPiSPIDataRW(SPI_CHANNEL, spi_data, 4) == -1) {
            fprintf(stderr, "Error reading SPI data: %s\n", strerror(errno));
            retries++;
            delay(10); // Small delay before retrying
            continue;
        }

        // Parse the data
        int32_t raw_thermocouple = (spi_data[0] << 24) | (spi_data[1] << 16) | (spi_data[2] << 8) | spi_data[3];

        // Check for fault bits
        if (raw_thermocouple & 0x7) {
            data.fault_detected = true;
            break; // Exit retry loop on fault
        }

        // Convert thermocouple temperature (signed 14-bit value)
        int32_t thermocouple_temperature_raw = raw_thermocouple >> 18;
        data.thermocouple_temperature = thermocouple_temperature_raw * 0.25;

        // Convert internal temperature (signed 12-bit value)
        int32_t internal_temperature_raw = (raw_thermocouple >> 4) & 0xFFF;
        data.internal_temperature = internal_temperature_raw * 0.0625;

        // Successfully read data, exit retry loop
        retries = SPI_RETRIES; // Exit retry loop
    }

    if (retries == SPI_RETRIES) {
        fprintf(stderr, "Error: Failed to read data after multiple retries.\n");
        data.thermocouple_temperature = -999.0; // Indicate error
        data.internal_temperature = -999.0;
        data.fault_detected = true;
    }

    return data;
}

// Function to control the fan speed
int control_fan(float temperature) {
    int fan_speed;

    // Scale temperature to fan speed (0-100%)
    if (temperature < MIN_TEMP) {
        fan_speed = 0;
    } else if (temperature > MAX_TEMP) {
        fan_speed = 100;
    } else {
        fan_speed = (int)(((temperature - MIN_TEMP) / (MAX_TEMP - MIN_TEMP)) * 100.0);
    }

    // Set PWM duty cycle
    pwmWrite(FAN_GPIO, fan_speed);

    return fan_speed;
}

// Function to log data to a file
void log_data(float thermocouple_temperature, float internal_temperature, int fan_speed) {
    time_t now = time(NULL);
    struct tm *t = localtime(&now);
    char timestamp[20];
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", t);

    if (log_file != NULL) {
        fprintf(log_file, "%s, %.2f, %.2f, %d\n", timestamp, thermocouple_temperature, internal_temperature, fan_speed);
        fflush(log_file); // Ensure data is written to disk
    } else {
        fprintf(stderr, "Error: Log file is not open.\n");
    }
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Received signal %d, shutting down...\n", signal);

    // Turn off fan
    pwmWrite(FAN_GPIO, 0);

    // Close log file
    if (log_file != NULL) {
        fclose(log_file);
    }

    exit(0);
}

int main() {
    if (initialize() != 0) {
        fprintf(stderr, "Initialization failed. Exiting.\n");
        return 1;
    }

    printf("Temperature monitoring and fan control started. Press Ctrl+C to exit.\n");

    while (program_running) {
        sensor_data_t sensor_data = read_max31855();

        if (!sensor_data.fault_detected) {
            int fan_speed = control_fan(sensor_data.thermocouple_temperature);
            log_data(sensor_data.thermocouple_temperature, sensor_data.internal_temperature, fan_speed);
        } else {
            fprintf(stderr, "Fault detected in MAX31855 data.\n");
        }

        delay(1000); // 1 second delay
    }

    return 0;
}

