#define I2C_ADDR 0x53  

int main(void)
{
    int fd, i, j, reg, value, data[6], prox, uva, uvb, als;
    char string[50];
    FILE *file;

    if ((fd = wiringPiI2CSetup(I2C_ADDR)) < 0)
    {
        printf("wiringPiI2CSetup failed: %d\n", fd);
        return 1;
    }

    if ((file = fopen("sensor_log.txt", "w")) == NULL)
    {
        printf("Failed to open file\n");
        return 1;
    }

    while (1)
    {
        for (i = 0; i < 6; i++)
        {
            reg = 0x80 | (i << 2);
            data[i] = wiringPiI2CReadReg8(fd, reg);
        }

        prox = (data[0] & 0x3FF) * 256 + (data[1] & 0xFF);
        uva = (data[2] & 0xFF) * 256 + (data[3] & 0xFF);
        uvb = (data[4] & 0xFF) * 256 + (data[5] & 0xFF);
        als = (data[1] & 0xFF) * 256 + (data[0] & 0x3F) * 64;

        time_t now = time(NULL);
        struct tm *t = localtime(&now);
        strftime(string, sizeof(string), "%Y-%m-%d %H:%M:%S", t);

        fprintf(file, "%s, Proximity: %d, UV Index: %d (UVA: %d, UVB: %d), ALS: %d\n", string, prox, uvb, uva, uvb, als);
        fflush(file);

