#define SI1153_REG_ALS_IR_DATA0 0x12
#define SI1153_REG_UV_INDEX0 0x2C
#define SI1153_REG_PROX_DATA0 0x24

int i2c_handle;
volatile sig_atomic_t program_running = 1;

// Function prototypes
int readProximity(int handle);
int readALS(int handle);
int readUVIndex(int handle);
void signal_handler(int signal);

/**
 * @brief Reads the proximity value from the Si1153 sensor.
 *
 * @param handle The I2C handle.
 * @return The proximity value, or -1 on error.
 */
int readProximity(int handle) {
    int proximity = i2cReadByteData(handle, SI1153_REG_PROX_DATA0);
    if (proximity < 0) {
        fprintf(stderr, "Error reading proximity data: %d\n", proximity);
        return -1;
    }
    return proximity;
}

/**
 * @brief Reads the ambient light sensor value from the Si1153 sensor.
 *
 * @param handle The I2C handle.
 * @return The ALS value, or -1 on error.
 */
int readALS(int handle) {
    int als_vis_low = i2cReadByteData(handle, SI1153_REG_ALS_VIS_DATA0);
    int als_vis_high = i2cReadByteData(handle, SI1153_REG_ALS_VIS_DATA0 + 1);
    if (als_vis_low < 0 || als_vis_high < 0) {
        fprintf(stderr, "Error reading ALS data: low=%d, high=%d\n", als_vis_low, als_vis_high);
        return -1;
    }

    int als = (als_vis_high << 8) | als_vis_low;
    return als;
}

/**
 * @brief Reads the UV index from the Si1153 sensor.
 *
 * @param handle The I2C handle.
 * @return The UV index, or -1 on error.
 */
int readUVIndex(int handle) {
    int uv_index = i2cReadByteData(handle, SI1153_REG_UV_INDEX0);
    if (uv_index < 0) {
        fprintf(stderr, "Error reading UV index: %d\n", uv_index);
        return -1;
    }
    return uv_index;
}

void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

int main() {
    // Initialize pigpio
    if (gpioInitialise() < 0) {
        fprintf(stderr, "pigpio initialisation failed\n");
        return 1;
    }

    // Configure PIR sensor GPIO as input
    gpioSetMode(PIR_GPIO, PI_INPUT);

    // Open I2C connection
    i2c_handle = i2cOpen(I2C_BUS, SI1153_ADDR, 0);
    if (i2c_handle < 0) {
        fprintf(stderr, "Failed to open I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set up signal handling for Ctrl+C
    signal(SIGINT, signal_handler);

    printf("Motion-triggered sensor logging started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Read PIR sensor
        int motion_detected = gpioRead(PIR_GPIO);

        if (motion_detected == 1) {
            // Motion detected, read and log sensor data
            time_t rawtime;
            struct tm *timeinfo;
            char timestamp[80];

            time(&rawtime);
            timeinfo = localtime(&rawtime);

            strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

            int proximity = readProximity(i2c_handle);
            int als = readALS(i2c_handle);
            int uv_index = readUVIndex(i2c_handle);

            if (proximity != -1 && als != -1 && uv_index != -1) {
                FILE *fp = fopen("sensor_log.txt", "a");
                if (fp != NULL) {
                    fprintf(fp, "%s, %d, %d, %d\n", timestamp, proximity, als, uv_index);
                    fclose(fp);
                    printf("Data logged: %s, Proximity: %d, ALS: %d, UV Index: %d\n", timestamp, proximity, als, uv_index);

                    // Simulate window tint adjustment based on UV index
                    if (uv_index > 5) {
                        printf("Simulating window tint darkening due to high UV index.\n");
                    }
                } else {
                    fprintf(stderr, "Error opening sensor_log.txt for writing\n");
                }
            } else {
                fprintf(stderr, "Error reading sensor data, skipping logging.\n");
            }

            // Debounce: wait a short period before checking for motion again
            gpioDelay(200); // 200ms
        } else {
            // No motion detected, sleep for a short interval
            gpioDelay(100); // 100ms
        }
    }

    // Cleanup
    i2cClose(i2c_handle);
    gpioTerminate();

    return 0;
}

