#define SI1153_REG_MEASRATE1 0x12
#define SI1153_REG_MEASRATE2 0x13
#define SI1153_REG_COMMAND 0x07
#define SI1153_REG_RESET 0x0A

// Function to read a register from the Si1153
int readSi1153Register(int fd, int reg) {
    int result = wiringPiI2CReadReg8(fd, reg);
    if (result < 0) {
        fprintf(stderr, "Error reading register 0x%02X\n", reg);
        return -1;
    }
    return result;
}

// Function to write a register to the Si1153
int writeSi1153Register(int fd, int reg, int value) {
    int result = wiringPiI2CWriteReg8(fd, reg, value);
    if (result < 0) {
        fprintf(stderr, "Error writing to register 0x%02X\n", reg);
        return -1;
    }
    return 0;
}

// Function to initialize the Si1153 sensor
int initializeSi1153(int fd) {
    // Reset the sensor
    if (writeSi1153Register(fd, SI1153_REG_COMMAND, 0x01) < 0) return -1;
    usleep(10000); // Wait for reset to complete (at least 10ms)
    if (writeSi1153Register(fd, SI1153_REG_RESET, 0x00) < 0) return -1;

    // Set UV Index Measurement Rate
    if (writeSi1153Register(fd, SI1153_REG_MEASRATE0, 0x02) < 0) return -1; // 160ms integration time
    if (writeSi1153Register(fd, SI1153_REG_MEASRATE1, 0x00) < 0) return -1;
    if (writeSi1153Register(fd, SI1153_REG_MEASRATE2, 0x00) < 0) return -1;

    // Enable UV Index Measurement
    if (writeSi1153Register(fd, SI1153_REG_INTCFG, 0x01) < 0) return -1; // Enable UV Index

    return 0;
}

// Function to read the proximity, ALS, and UV index data from the Si1153
int readSi1153Data(int fd, int *proximity, int *ambient_light, int *uv_index) {
    // Read the proximity data
    *proximity = readSi1153Register(fd, SI1153_REG_PS0DATA0);
    if (*proximity < 0) return -1;
    *proximity |= (readSi1153Register(fd, SI1153_REG_PS0DATA1) << 8);

    // Read the ambient light data
    *ambient_light = readSi1153Register(fd, SI1153_REG_ALSVISDATA0);
    if (*ambient_light < 0) return -1;
    *ambient_light |= (readSi1153Register(fd, SI1153_REG_ALSVISDATA1) << 8);

    // Read the UV index data
    *uv_index = readSi1153Register(fd, SI1153_REG_UVAINDEX0);
    if (*uv_index < 0) return -1;
    *uv_index |= (readSi1153Register(fd, SI1153_REG_UVAINDEX1) << 8);

