    if (wiringPiSetupGpio() == -1) {
        fprintf(stderr, "Error initializing wiringPi: %s (errno: %d)\n", strerror(errno), errno);
        return 1;
    }

    // Set GPIO pin as input with pull-up resistor
    pinMode(GPIO_PIN, INPUT);
    pullUpDnControl(GPIO_PIN, PUD_UP);

    // Allocate circular buffer
    circularBuffer = (Event*) malloc(BUFFER_SIZE * sizeof(Event));
    if (circularBuffer == NULL) {
        fprintf(stderr, "Error allocating memory for circular buffer: %s (errno: %d)\n", strerror(errno), errno);
        return 1;
    }

    // Register interrupt handler for both rising and falling edges
    if (wiringPiISR(GPIO_PIN, INT_EDGE_BOTH, &tiltSwitchInterruptHandler) != 0) {
        fprintf(stderr, "Error setting up interrupt handler: %s (errno: %d)\n", strerror(errno), errno);
        free(circularBuffer);
        return 1;
    }

    // Register signal handler for SIGINT (Ctrl+C)
    signal(SIGINT, signalHandler);

    // Main loop
