void log_lux_value(float lux);
void signal_handler(int signal);

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    if (signal == SIGINT) {
        printf("Caught SIGINT, exiting gracefully.\n");
        terminate = 1;
    }
}

// Function to read lux value from BH1750 sensor
float read_lux() {
    char buffer[2];
    int count;
    float lux;

    // Set the BH1750 to continuous high-resolution mode
    count = i2cWriteDevice(i2c_handle, (char *)&CONTINUOUS_HIGH_RES_MODE, 1);
    if (count != 1) {
        fprintf(stderr, "Error writing to I2C device: %d\n", count);
        return -1.0;
    }

    // Wait for measurement to complete
    gpioDelay(BH1750_MEASUREMENT_DELAY);

    // Read two bytes from the sensor
    count = i2cReadDevice(i2c_handle, buffer, 2);
    if (count != 2) {
        fprintf(stderr, "Error reading from I2C device: %d\n", count);
        return -1.0;
    }

    // Convert the raw data to lux
    lux = (float)((buffer[0] << 8) | buffer[1]) / 1.2;

    return lux;
}

