    i2c_handle = i2cOpen(1, BH1750_I2C_ADDR, 0); // Bus 1, address 0x23, no flags
    if (i2c_handle < 0) {
        fprintf(stderr, "Error opening I2C device: %d\n", i2c_handle);
        gpioTerminate();
        return 1;
    }

    // Set GPIO24 as output
    gpioSetMode(LED_GPIO, PI_OUTPUT);

    // Set PWM range to 256 (0-255)
    gpioSetPWMfrequency(LED_GPIO, 1000); // Adjust frequency as needed
    gpioSetPWMrange(LED_GPIO, DUTY_CYCLE_MAX);

    // Set initial LED brightness to 0
    set_led_brightness(0);

    // Register signal handler for graceful shutdown
    signal(SIGINT, signal_handler);

    // Main loop
    while (!terminate) {
        // Read lux value from sensor
        lux = read_lux();

        if (lux > 0) {
            // Calculate the difference between the current and last lux values
            float diff = lux - last_lux;

            // Check if the lux value has changed significantly
            if (fabs(diff) >= LUX_THRESHOLD) {
