                set_led_brightness(brightness);
            }
        } else {
            fprintf(stderr, "Error reading lux value, using last valid value.\n");
        }

        // Delay for a short period
        gpioDelay(100000); // 100ms
    }

    // Shutdown sequence
    printf("Shutting down...\n");
    set_led_brightness(0); // Turn off LED
    i2cClose(i2c_handle);   // Close I2C connection
    gpioTerminate();       // Terminate pigpio

    return 0;
}

